export const scrollViewApiJs = `import { LayerScoper } from 'layer-scoper';
import { LayerScoperScrollView } from 'layer-scoper/plugin/LayerScoperScrollView.js';

const controllerCase = new LayerScoper();
const scrollViewCase = new LayerScoperScrollView({
  id: 'layer-scrollview-id',
  scrollDirection: 'vertical',
});

controllerCase.initController({
  id: 'layer-scrollview-id',
  className: 'incontroll',
  defaultPoint: { y: 1, x: 1 },
  scrollViewComponentConfig: [
    {
      scope: 1,
      target: scrollViewCase,
    },
  ],
});

// 当内容更新后，调用 updateScrollView 刷新滚动条尺寸/位置
setTimeout(() => {
  const container = document.querySelector('#layer-scrollview-id .layerscoper-scrollview-content-inner');
  if (container) {
    container.innerHTML += '<p>新增内容 - 3</p><p>新增内容 - 4</p><p>新增内容 - 5</p>';
  }
  scrollViewCase.updateScrollView();
}, 1000);
`;
